tool.command:
exec 3>&1 4>&2;
exec > enzywizard.log 2>&1;

#set $mut_clean_name = $mut_clean_report_path.element_identifier
mkdir -p wt_input mut_input &&
unzip -q '$wt_input_zip' -d wt_input &&
unzip -q '$mut_input_zip' -d mut_input &&
find wt_input mut_input -type f \( -name 'clean_report*.json' -o -name 'substrate_report*.json' -o -name 'mut_clean_report*.json' \) -delete &&
find wt_input mut_input -type f -name '*.json' ! -name '*report*.json' -delete &&
if ! find wt_input -type f -name '*1ZG4_WT*.json' | grep -q .; then echo 'The wt_input_zip test data does not match the mutation-clean report: expected upstream mut-integrate WT reports for cleaned_1ZG4_WT. Replace test-data/wt_input.zip with a zip built from bioinfbrad/enzywizard-mut-integrate examples/wt_input.' >&4; find wt_input -type f | sort >&4; exit 1; fi &&
if ! find mut_input -type f -name '*1ZG6_S70G*.json' | grep -q .; then echo 'The mut_input_zip test data does not match the mutation-clean report: expected upstream mut-integrate mutant reports for cleaned_1ZG6_S70G. Replace test-data/mut_input.zip with a zip built from bioinfbrad/enzywizard-mut-integrate examples/mut_input.' >&4; find mut_input -type f | sort >&4; exit 1; fi &&
ln -s '$mut_clean_report_path' '$mut_clean_name' &&
if command -v enzywizard-mut-integrate >/dev/null 2>&1; then
    enzywizard-mut-integrate -i '$mut_clean_name' -w wt_input -m mut_input -wo wt_output -mo mut_output $advanced.strict;
elif command -v enzywizard-mut_integrate >/dev/null 2>&1; then
    enzywizard-mut_integrate -i '$mut_clean_name' -w wt_input -m mut_input -wo wt_output -mo mut_output $advanced.strict;
else
    python -m enzywizard_mut_integrate.cli -i '$mut_clean_name' -w wt_input -m mut_input -wo wt_output -mo mut_output $advanced.strict;
fi;
status=\$?;
echo "---- files in Galaxy job working directory ----" >&4;
find . -maxdepth 5 -type f | sort >&4;
if [ "\$status" -ne 0 ]; then cat enzywizard.log >&4; exit "\$status"; fi;
if ! find wt_output mut_output -maxdepth 2 -type f -name '*.json' | grep -q .; then echo "No EnzyWizard Mut Integrate output JSON files were produced." >&4; cat enzywizard.log >&4; [ -f log.txt ] && cat log.txt >&4; exit 1; fi;
